export const getNodesByCategory = (category: QuestCategory): Omit<SkillNode, 'level' | 'xp' | 'lastReviewDate' | 'isUnlocked'>[] => {
  return SKILL_TREE_NODES.filter(node => node.category === category).sort((a, b) => a.order - b.order)
}

export const getRootNode = (category: QuestCategory): Omit<SkillNode, 'level' | 'xp' | 'lastReviewDate' | 'isUnlocked'> | undefined => {
  return SKILL_TREE_NODES.find(node => node.category === category && node.parentId === null)
}

export const getChildNodes = (parentId: string): Omit<SkillNode, 'level' | 'xp' | 'lastReviewDate' | 'isUnlocked'>[] => {
  return SKILL_TREE_NODES.filter(node => node.parentId === parentId).sort((a, b) => a.order - b.order)
}

export const getReviewIntervalByLevel = (level: number): number => {
  const intervals = [0, 3, 7, 14, 30]
  return intervals[Math.min(level, 4)] ?? 0
}